/// 
/// Key changes:
///   1. Thread.Abort()           → CancellationTokenSource.Cancel()
///   2. ThreadAbortException     → OperationCanceledException
///   3. Thread.ResetAbort()      → check token.IsCancellationRequested, decide to continue
///   4. volatile bool _running   → CancellationToken (single mechanism, no split signals)
///   5. Thread.Sleep(2000) wait  → Thread.Join(timeout) (deterministic)
///   6. GetNextItem() must accept CancellationToken so blocked calls can be interrupted
/// </summary>
public class BackgroundProcessor : IDisposable
{
    private Thread? _workerThread;
    private CancellationTokenSource? _cts;

    public void Start()
    {
        _cts = new CancellationTokenSource();
        _workerThread = new Thread(() => ProcessLoop(_cts.Token));
        _workerThread.IsBackground = true;
        _workerThread.Start();
    }

    private void ProcessLoop(CancellationToken token)
    {
        while (!token.IsCancellationRequested)
        {
            try
            {
                // Pass the token so blocking calls can be interrupted cooperatively.
                var item = GetNextItem(token);
                ProcessItem(item);
            }
            catch (OperationCanceledException) when (token.IsCancellationRequested)
            {
                // Cancellation was requested — clean up partial work,
                // then let the while-loop condition exit naturally.
                RollbackCurrentTransaction();
            }
            finally
            {
                FlushBuffers();
            }
        }
    }

    public void Stop()
    {
        if (_cts is null || _workerThread is null)
            return;

        // Signal cooperative cancellation (replaces Thread.Abort).
        _cts.Cancel();

        // Give the thread time to finish gracefully (replaces Thread.Sleep + Abort).
        // Join returns true if the thread exits within the timeout.
        if (!_workerThread.Join(TimeSpan.FromSeconds(2)))
        {
            // Thread did not exit in time. In modern .NET there is no way to
            // forcibly kill a managed thread. Log a warning; see pitfalls below.
            Console.Error.WriteLine(
                "Warning: worker thread did not exit within the timeout.");
        }
    }

    public void Dispose()
    {
        Stop();
        _cts?.Dispose();
        _cts = null;
    }

    // --- stubs for illustration ---

    private object GetNextItem(CancellationToken token)
    {
        // CRITICAL: If this was a blocking call (e.g., BlockingCollection.Take,
        // database poll, socket read), you MUST use an overload that accepts
        // a CancellationToken so it can be interrupted.
        //
        // Examples:
        //   _queue.Take(token);                         // BlockingCollection
        //   await reader.ReadAsync(token);               // Channel<T>
        //   token.WaitHandle.WaitOne(pollInterval);      // replaces Thread.Sleep
        token.ThrowIfCancellationRequested();
        return new object();
    }

    private void ProcessItem(object item) { }
    private void RollbackCurrentTransaction() { }
    private void FlushBuffers() { }
}

